from haystack.components.generators import OpenAIGenerator
from vex import Guardrail

class AgeAppropriateFilter:
    def __init__(self):
        self.vex_guard = Guardrail("education-age-appropriate")

    def __call__(self, generated_text: str, student_age: int) -> str:
        verdict = self.vex_guard.enforce(
            text=generated_text,
            context={"age": student_age, "domain": "k12-education"}
        )
        if verdict.blocked:
            return "Content blocked for age appropriateness."
        return generated_text

# Usage in generator pipeline
generator = OpenAIGenerator()
filter_component = AgeAppropriateFilter()

pipeline.add_component("generator", generator)
pipeline.add_component("age_filter", filter_component)
pipeline.connect("generator", "age_filter")

import json
from haystack import Pipeline
from vex import AuditLogger

class FERPACompliantLogger:
    def __init__(self):
        self.logger = AuditLogger(
            policy_id="ferpa-education",
            retention_days=1095  # 3 years
        )

    def run(self, **kwargs) -> dict:
        # Log query, docs, response, student_id (hashed)
        audit_event = {
            "student_id_hash": kwargs.get("student_hash"),
            "query": kwargs["query"],
            "response": kwargs["response"],
            "timestamp": "now()"
        }
        self.logger.record(audit_event)
        return {"audit_id": self.logger.last_audit_id}

# Add to pipeline
pipeline = Pipeline()
pipeline.add_component("ferpa_logger", FERPACompliantLogger())
pipeline.connect("generator", "ferpa_logger")
